"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[6615],{1598:e=>{e.exports=JSON.parse('{"version":{"pluginId":"examples","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","label":"Examples","href":"/examples/overview/","docId":"overview/index","unlisted":false},{"type":"category","collapsed":false,"label":"Agents","items":[{"type":"link","label":"Calling Agents","href":"/examples/agents/calling_agents","docId":"agents/calling_agents","unlisted":false},{"type":"link","label":"Changing the System Prompt","href":"/examples/agents/agent_system_prompt","docId":"agents/agent_system_prompt","unlisted":false},{"type":"link","label":"Adding a tool","href":"/examples/agents/adding_tool","docId":"agents/adding_tool","unlisted":false},{"type":"link","label":"Adding a workflow","href":"/examples/agents/adding_workflow","docId":"agents/adding_workflow","unlisted":false},{"type":"link","label":"Supervisor Agent","href":"/examples/agents/supervisor_agent","docId":"agents/supervisor_agent","unlisted":false},{"type":"link","label":"Image Analysis Agent","href":"/examples/agents/image_analysis","docId":"agents/image_analysis","unlisted":false},{"type":"link","label":"Using Voice with Agents","href":"/examples/agents/using_voice","docId":"agents/using_voice","unlisted":false},{"type":"link","label":"Dynamic Context","href":"/examples/agents/dynamic_context","docId":"agents/dynamic_context","unlisted":false}],"collapsible":true},{"type":"category","label":"Workflows","collapsed":false,"items":[{"type":"link","label":"Running Workflows","href":"/examples/workflows/running_workflows","docId":"workflows/running_workflows","unlisted":false},{"type":"link","label":"Sequential Execution","href":"/examples/workflows/sequential_steps","docId":"workflows/sequential_steps","unlisted":false},{"type":"link","label":"Parallel Execution","href":"/examples/workflows/parallel_steps","docId":"workflows/parallel_steps","unlisted":false},{"type":"link","label":"Conditional Branching","href":"/examples/workflows/conditional_branching","docId":"workflows/conditional_branching","unlisted":false},{"type":"link","label":"Array as Input","href":"/examples/workflows/array_input","docId":"workflows/array_input","unlisted":false},{"type":"link","label":"Calling an Agent Inside a Step","href":"/examples/workflows/calling_agent","docId":"workflows/calling_agent","unlisted":false},{"type":"link","label":"Agent as a Step","href":"/examples/workflows/agent_step","docId":"workflows/agent_step","unlisted":false},{"type":"link","label":"Tool as a Step","href":"/examples/workflows/tool_step","docId":"workflows/tool_step","unlisted":false},{"type":"link","label":"Human In-the-Loop Workflow","href":"/examples/workflows/human_loop","docId":"workflows/human_loop","unlisted":false}],"collapsible":true}]},"docs":{"agents/adding_tool":{"id":"agents/adding_tool","title":"Adding a tool","description":"When building AI agents, you often need to extend their capabilities with external data or functionality. Timbal lets you pass tools to an agent using the tools parameter. Tools give agents a way to call specific functions, such as fetching data or performing calculations, to help answer a user\'s query.","sidebar":"docsSidebar"},"agents/adding_workflow":{"id":"agents/adding_workflow","title":"Adding a workflow","description":"When building AI agents, it can be useful to combine them with workflows that perform multi-step tasks or fetch structured data. Timbal lets you pass workflows to an agent using the workflows parameter. Workflows provide a way for agents to trigger predefined sequences of steps, giving them access to more complex operations than a single tool can provide.","sidebar":"docsSidebar"},"agents/agent_system_prompt":{"id":"agents/agent_system_prompt","title":"Changing the System Prompt","description":"","sidebar":"docsSidebar"},"agents/calling_agents":{"id":"agents/calling_agents","title":"Calling Agents","description":"There are multiple ways to interact with agents created using Timbal. Below you will find examples of how to call agents using workflow steps or tools.","sidebar":"docsSidebar"},"agents/dynamic_context":{"id":"agents/dynamic_context","title":"Dynamic Context","description":"Dynamic agents adapt their behavior and capabilities at runtime based on contextual input. Instead of relying on fixed configurations, they adjust to users, environments, or scenarios, enabling a single agent to serve personalized, context-aware responses.","sidebar":"docsSidebar"},"agents/image_analysis":{"id":"agents/image_analysis","title":"Image Analysis Agent","description":"When building AI applications, you often need agents that can analyze and understand visual content. Timbal lets you create image analysis agents that can identify objects, describe scenes, and answer questions about visual content using the tools parameter.","sidebar":"docsSidebar"},"agents/supervisor_agent":{"id":"agents/supervisor_agent","title":"Supervisor Agent","description":"When building complex AI applications, you often need multiple specialized agents to collaborate on different aspects of a task. A supervisor agent enables one agent to act as a supervisor, coordinating the work of other agents, each focused on their own area of expertise. This structure allows agents to delegate, collaborate, and produce more advanced outputs than any single agent alone.","sidebar":"docsSidebar"},"agents/using_voice":{"id":"agents/using_voice","title":"Using Voice with Agents","description":"Giving your Agent a Voice","sidebar":"docsSidebar"},"overview/index":{"id":"overview/index","title":"Examples","description":"","sidebar":"docsSidebar"},"workflows/agent_step":{"id":"workflows/agent_step","title":"Agent as a Step","description":"","sidebar":"docsSidebar"},"workflows/array_input":{"id":"workflows/array_input","title":"Array as Input","description":"Some workflows need to perform the same operation on every item in an array. This example demonstrates how to iterate over a list of strings and apply the same step to each one, producing a transformed array as the output.","sidebar":"docsSidebar"},"workflows/calling_agent":{"id":"workflows/calling_agent","title":"Calling an Agent Inside a Step","description":"Workflows can call agents to generate dynamic responses from within a step. This example shows how to define an agent and invoke it directly from within a workflow step. The workflow takes a city name as input and returns a fact about the corresponding city.","sidebar":"docsSidebar"},"workflows/conditional_branching":{"id":"workflows/conditional_branching","title":"Conditional Branching","description":"Workflows often need to follow different paths based on a condition. These examples demonstrate how to create conditional flows using Timbal\'s workflow orchestration capabilities.","sidebar":"docsSidebar"},"workflows/human_loop":{"id":"workflows/human_loop","title":"Human In-the-Loop Workflow","description":"Use human-in-the-loop workflows to pause execution at specific steps for human input, decision-making, or tasks that require judgment beyond automation.","sidebar":"docsSidebar"},"workflows/parallel_steps":{"id":"workflows/parallel_steps","title":"Parallel Execution","description":"Workflows often need to run multiple operations at the same time. These examples demonstrate how to execute steps or workflows concurrently and merge their results using Timbal\'s automatic parallel execution capabilities.","sidebar":"docsSidebar"},"workflows/running_workflows":{"id":"workflows/running_workflows","title":"Running Workflows","description":"Workflows can be run from different environments. These examples demonstrate how to execute a workflow using a command line script or by calling the workflow directly from a client-side component.","sidebar":"docsSidebar"},"workflows/sequential_steps":{"id":"workflows/sequential_steps","title":"Sequential Execution","description":"Many workflows involve executing steps one after another in a defined order. This example demonstrates how to use .link() to build a simple sequential workflow where the output of one step becomes the input of the next.","sidebar":"docsSidebar"},"workflows/tool_step":{"id":"workflows/tool_step","title":"Tool as a Step","description":"Workflows can include tools as steps. This example shows how to define a tool as a step in your Timbal workflow.","sidebar":"docsSidebar"}}}}')}}]);